SELECT make_name, headquarters
FROM makes
WHERE make_name LIKE '%General%' AND founding_year > 1900;

SELECT make_name, contact_email
FROM makes
WHERE market_share = (SELECT MAX(market_share) FROM makes);

SELECT *
FROM vehicle_emissions
WHERE co2_emission_grams_per_mile > 600;

SELECT make_name, market_share
FROM makes
WHERE founding_year >= 2000 AND market_share > 20;

SELECT makes.make_name, models.model_name, models.production_start_year, models.production_end_year, models.model_description
FROM makes
JOIN models ON makes.make_id = models.make_id;
